sql:
SELECT contract_name
FROM contracts
WHERE contract_id IN (
    SELECT contract_id
    FROM trading_strategies
);

SELECT strategy_name, parameters 
FROM trading_strategies 
WHERE strategy_type = 'momentum' AND created_at > '2023-05-02 09:00:00';

external_knowledge:
- 'momentum' refers to a type of trading strategy that capitalizes on the continuation of a trend;
- 'active' indicates that the strategy is currently in use;
- 'big board' is a colloquial term for the NYSE (New York Stock Exchange).

sql:
SELECT DISTINCT c.contract_id, c.contract_name
FROM contracts c
INNER JOIN price_alerts pa ON c.contract_id = pa.contract_id;

SELECT contracts.contract_name, market_reports.report_status
FROM contracts
INNER JOIN market_reports ON contracts.contract_id = market_reports.contract_id;

SELECT DISTINCT user_id
FROM user_access
WHERE access_type = 'download' AND ip_address IN (
    SELECT ip_address
    FROM user_access
    WHERE user_id IN (
        SELECT created_by
        FROM market_reports
    )
);

external_knowledge:
- 'shining stars' metaphorically refers to contracts with high-quality data;
- 'observed more than thrice' means the high-quality data for these contracts appears more than three times;
- 'vast cosmos of the China Zhengzhou Commodity Exchange' is a metaphor for the extensive market of the China Zhengzhou Commodity Exchange.

sql:
SELECT COUNT(DISTINCT user_id)
FROM audit_logs
WHERE action = 'viewed market data';
